insert into public.csr_projects (title,category,status,description,impact_numbers,date,published) values
('Mangalam Chikitsalaya — a free hospital for Amlabad','community','completed','A hospital built at Amlabad Colliery in the memory of our founder, Late Shri Shree Gopal Agarwal, and inaugurated on his 60th birth anniversary by his wife, Smt. Urmil Agarwal. Treatment at the Chikitsalaya is provided free of charge to workers and the surrounding villages.','Free treatment · opened 18 Feb 2026','2026-02-18',true),
('Free health check-up camp','community','completed','Held alongside the Chikitsalaya''s inauguration, a team of specialist doctors screened residents for eye, dental, cardiac, diabetes and blood-pressure conditions, and advised each patient on treatment.','250+ patients screened','2026-02-18',true),
('Voluntary blood donation drive','community','completed','A blood donation drive held on the founder''s birth anniversary. Smt. Urmil Agarwal donated first, joined by company employees and villagers from around the colliery.','34 donors','2026-02-18',true),
('Plantation drive at the colliery','environment','completed','Dozens of saplings were planted across the Chikitsalaya premises in the founder''s memory, carrying a message of environmental care and green cover at the colliery.','Dozens of saplings planted','2026-02-18',true),
('Black Diamond Awards — recognising our people','safety','ongoing','An employee recognition scheme rewarding outstanding work at the colliery. Its ''Emergency Warrior'' honour recognised Sukhdev Rajwar, Bharat Rajwar and Suraj Rajwar, who restored an underground machine breakdown in thirty minutes. Awards carry a certificate, a cash incentive and a holiday package, and are recorded in the employee''s service record.','Certificate + Rs 5,000-50,000 incentive','2026-04-29',true);
